# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib3
import base64

http = urllib3.PoolManager()

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    enrichment_data = {}
    
    # Check for X-Enrich-URL headers (can be multiple)
    enrich_urls = []
    for header_name, header_values in headers.items():
        if header_name.lower() == 'x-enrich-url':
            for header_value in header_values:
                enrich_urls.append(header_value['value'])
    
    # Fetch data from each enrichment URL
    for url in enrich_urls:
        try:
            response = http.request('GET', url, timeout=2.0)
            if response.status == 200:
                try:
                    data = json.loads(response.data.decode('utf-8'))
                    enrichment_data[url] = data
                except:
                    enrichment_data[url] = response.data.decode('utf-8')
            else:
                enrichment_data[url] = {'error': f'HTTP {response.status}'}
        except Exception as e:
            enrichment_data[url] = {'error': str(e)}
    
    # Add enriched data as a new header
    if enrichment_data:
        enriched_json = json.dumps(enrichment_data)
        # Base64 encode to handle special characters
        enriched_base64 = base64.b64encode(enriched_json.encode('utf-8')).decode('utf-8')
        
        headers['x-enriched-data'] = [{
            'key': 'X-Enriched-Data',
            'value': enriched_base64
        }]
    
    return request